        color: var(--text-heading);
    }
    .user-post-settings svg{
        width: 20px;
        height: 20px;
    }
    .setting-modal{
        right: 0;
        bottom: 25px;
        width: 180px;
        height: 80px;
        font-size: 0.75rem;
    }
    .toolbar {
        display: flex;
        justify-content: center;
        height: 100%;
        width: 100%;
    }
    .toolbar-bttns {
        display: flex;
        width: 16px;
        height: 16px;
        justify-content: center;
        align-items: center;
        padding: 0.5rem;
        border-radius: 10px;
        cursor: pointer;
        transition: ease-in-out 0.1s;
        user-select: none;
    }
    .editor-save-bttn {
        display: flex;
        justify-content: center;
        align-items: center;
        padding: 0.2rem 0.8rem;
        font-size: 0.8rem;
        border-radius: 15px;
        margin-right: 1rem;
        background-color: rgb(255, 255, 255);
        color: rgb(4, 20, 29);
        font-weight: 600;
        cursor: pointer;
        border: hidden;
    }

}

